import type { ChangeEvent } from 'react';

export type CheckBoxValue = string | number | boolean | undefined;

/**
 * @public
 * onChange 事件的参数
 */
export interface CheckBoxChangeEvent {
  target: {
    value?: CheckBoxValue;
    checked: boolean;
    type: 'checkbox';
  };
  /**
   * 阻止时间冒泡
   */
  stopPropagation: () => void;
  preventDefault: () => void;
  /**
   * react 的合成事件
   */
  reactEvent: ChangeEvent<HTMLInputElement>;
  /**
   * 原生事件
   */
  nativeEvent: Event;
}
